time = data(:,1); % 提取时间数据
voltage = data(:,2); % 提取电压数据
current = data(:,3); % 提取电流数据
sampling_frequency = 10; % 采样频率为10Hz
N = length(time); % 数据点数

% 计算频率
frequency = (0:N-1) * sampling_frequency / N;

% 对电流信号进行FFT变换
current_fft = fft(current);

% 计算电化学阻抗
impedance = voltage ./ current_fft .* exp(-1i*pi/2) * 4.125;

% 画出奈奎斯特图
figure;
plot(real(impedance), imag(impedance)); % 实部为x轴，虚部为y轴
xlabel('Real(Z)'); ylabel('Imaginary(Z)');
title('Nyquist Plot');
